+/// Helper to list conversations in a specific directory
+fn listConversationsInDir(allocator: std.mem.Allocator, dir_path: []const u8, model_name: ?[]const u8) !void {
+    _ = model_name;
+
+    var dir = std.fs.cwd().openDir(dir_path, .{ .iterate = true }) catch |err| {
+        if (err == error.FileNotFound) {
+            std.debug.print("  No conversations found.\n", .{});
+            return;
+        }
+        return err;
+    };
+    defer dir.close();
+
+    var file_count: u32 = 0;
+    var total_entries: u64 = 0;
+
+    var iter = dir.iterate();
+    while (try iter.next()) |entry| {
+        if (entry.kind == .file and std.mem.endsWith(u8, entry.name, ".jsonl")) {
+            file_count += 1;
+
+            // Count lines in file
+            const file_path = try std.fmt.allocPrint(allocator, "{s}/{s}", .{ dir_path, entry.name });
+            defer allocator.free(file_path);
+
+            const file = std.fs.cwd().openFile(file_path, .{}) catch continue;
+            defer file.close();
+
+            var line_count: u64 = 0;
+            var buf: [4096]u8 = undefined;
+            var reader = file.reader();
+            while (reader.readUntilDelimiter(&buf, '\n')) |_| {
+                line_count += 1;
+            } else |_| {}
+
+            total_entries += line_count;
+
+            // Extract date from filename (YYYY-MM-DD.jsonl)
+            const date = entry.name[0 .. entry.name.len - 6]; // Remove ".jsonl"
+            std.debug.print("  {s}: {d} entries\n", .{ date, line_count });
+        }
+    }
+
+    if (file_count == 0) {
+        std.debug.print("  No conversations found.\n", .{});
+    } else {
+        std.debug.print("  Total: {d} files, {d} entries\n", .{ file_count, total_entries });
+    }
 }

